sql:
SELECT COUNT(event_id) AS error_event_count
FROM audit_events
WHERE event_severity = 'error';

SELECT event_severity, COUNT(event_id) AS event_count
FROM audit_events
GROUP BY event_severity;

SELECT event_id, event_message
FROM audit_events
WHERE event_severity = 'info';

SELECT signature, signature_type
FROM audit_signatures
WHERE signature_type = 'system';

SELECT signature_id, signature, signature_type, created_by
FROM audit_signatures
ORDER BY created_at DESC;

SELECT COUNT(*) 
FROM audit_signatures 
WHERE created_by = 'admin';

external_knowledge:
- "System shutdowns" refers to events with the audit signature 'Windows is shutting down'; 
- "Initiated" refers to the user role in the event; 
- "Year 2022" refers to the time range between '2022-01-01 00:00:00' and '2022-12-31 23:59:59'.
